import sys, json
data = json.load(sys.stdin)
json.dump(data, open('after-cpm-packages.json', 'w'), indent=2)

# Compare
baseline = json.load(open('baseline-packages.json'))
after = data

def get_packages(d):
    result = {}
    for proj in d['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(pname, pkg['id'])] = pkg['resolvedVersion']
    return result

b = get_packages(baseline)
a = get_packages(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(key)
    av = a.get(key)
    if bv == av:
        unchanged.append((key[0], key[1], bv))
    else:
        changes.append((key[0], key[1], bv, av))

if changes:
    print('CHANGES:')
    for c in changes:
        print(f'  {c[0]} | {c[1]} | {c[2]} -> {c[3]}')
else:
    print('NO CHANGES - conversion is fully version-neutral')

print()
print('UNCHANGED:')
for u in unchanged:
    print(f'  {u[0]} | {u[1]} | {u[2]}')
"

